  const greenBtn = document.querySelector('[data-ct-ref="5"]');
  if(greenBtn) {
    greenBtn.click();
    return 'clicked green';
  }
  // Find by text content
  const buttons = document.querySelectorAll('button');
  for(let btn of buttons) {
    if(btn.textContent.trim() === 'Green') {
      btn.click();
      return 'clicked green by text';
    }
  }
  return 'not found';
})()

(function() {
  // Find all buttons and check their computed style
  const buttons = document.querySelectorAll('button');
  for(let btn of buttons) {
    const style = window.getComputedStyle(btn);
    const bg = style.backgroundColor;
    if(bg.includes('green') || bg.includes('rgb(0, 128, 0)') || bg.includes('rgb(34, 197, 94)') || bg.includes('rgb(74, 222, 128)')) {
      btn.click();
      return 'Clicked green button with bg: ' + bg;
    }
  }
  // Try finding by text
  for(let btn of buttons) {
    if(btn.textContent.trim() === 'Green') {
      btn.click();
      return 'Clicked by text: Green';
    }
  }
  return 'No green button found';
})()
